Create focusa-pi-bridge.ts Pi extension skeleton.

CREATE: ~/.pi/agent/extensions/focusa-pi-bridge.ts

SKELETON:
  import type { ExtensionAPI } from '@mariozechner/pi-coding-agent';
  import { Type } from '@sinclair/typebox';

  export default function (pi: ExtensionAPI) {
    // State
    let wbmEnabled = false;
    let wbmContext: string | null = null;
    let cataloguedDecisions: string[] = [];
    let cataloguedFacts: string[] = [];

    // Register commands (doc 44 §10.3)
    pi.registerCommand('focusa-status', { description: 'Focusa daemon status', handler: async (args, ctx) => {
      const res = await fetch('http://127.0.0.1:8787/v1/health', {signal: AbortSignal.timeout(2000)});
      ctx.ui.notify(JSON.stringify(await res.json()), 'info');
    }});
    pi.registerCommand('focusa-stack', { ... });
    pi.registerCommand('focusa-pin', { ... });
    pi.registerCommand('focusa-suppress', { ... });
    pi.registerCommand('focusa-checkpoint', { ... });
    pi.registerCommand('focusa-rehydrate', { ... });
    pi.registerCommand('focusa-gate-explain', { ... });
    pi.registerCommand('wbm', { ... });  // From focusa-wzk bead

    // Hooks
    pi.on('before_agent_start', async (event, ctx) => { ... });  // Context injection
    pi.on('agent_end', async (event, ctx) => { ... });  // Work cataloguing
    pi.on('turn_start', async (event, ctx) => { ... });  // Status indicator
  }

API CALLS: All to http://127.0.0.1:8787/v1/* with 2s timeout + AbortSignal
FALLBACK: If Focusa unavailable, skip all hooks silently (fail-safe per doc 44 §11)

VERIFY: pi loads extension without errors. /focusa-status returns health JSON.
DEPENDS: Focusa daemon running
REF: doc 44 §10

Enforce TTL on semantic memories.

FILE: /home/wirebot/focusa/crates/focusa-core/src/memory/procedural.rs (or semantic.rs)
WHERE: In decay_tick() function, after procedural decay

ADD TTL check:
  // Enforce semantic memory TTLs
  let now = Utc::now();
  memory.semantic.retain(|key, record| {
    if let Some(ttl) = record.ttl {
      if now > record.created_at + ttl {
        tracing::info!(key, 'Semantic memory expired (TTL)');
        return false;  // Remove expired
      }
    }
    true
  });

